import java.io.StringReader;

/**
 * Service for validating XML Schema (XSD) content.
 */
public class SchemaValidationService {

    /**
     * Validates whether the provided string contains valid XML Schema content.
     *
     * @param schemaContent the XML Schema content as a string
     * @return true if the schema is valid, false otherwise
     */
    public boolean validateSchema(String schemaContent) {
        // Early validation for null or empty content
        if (schemaContent == null || schemaContent.trim().isEmpty()) {
            return false;
        }

        try {
            // Create SchemaFactory for XML Schema
            SchemaFactory factory = SchemaFactory.newInstance(XMLConstants.W3C_XML_SCHEMA_NS_URI);

            // Configure factory to be secure against XXE attacks
            factory.setProperty(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            factory.setProperty(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

            // Parse and compile the schema - this validates the schema structure
            Schema schema = factory.newSchema(new StreamSource(new StringReader(schemaContent)));

            // If schema compilation succeeds, it's valid
            return schema != null;

        } catch (Exception e) {
            // Log the exception in real implementation (commented out for brevity)
            // System.err.println("Schema validation failed: " + e.getMessage());
            return false;
        }
    }
}
